def count_distinct_elements(nums):
    """
    Returns the number of distinct elements in the list nums.
    The time complexity is O(n log n) due to sorting.
    """
    if not nums:
        return 0

    sorted_nums = sorted(nums)
    distinct_count = 1

    for i in range(1, len(sorted_nums)):
        if sorted_nums[i] != sorted_nums[i - 1]:
            distinct_count += 1

    return distinct_count

def array_to_string(arr):
    """
    Converts an array of integers to a string with values separated by commas.
    """
    return ','.join(map(str, arr))

def echo(input_string, flag=None):
    """
    Prints the input_string. If flag is '-n', it suppresses the trailing newline.
    """
    if flag == '-n':
        print(input_string, end='')
    else:
        print(input_string)
